using System.Text;

public static class CreditCardEncryptionUtility
{
    private const string EncryptionKey = "your_secret_key"; // Replace with your own secret key

    public static string Encrypt(string creditCardNumber)
    {
        var bytes = Encoding.UTF8.GetBytes(creditCardNumber);
        using (var aes = new AesCryptoServiceProvider())
