            aes.Key = Encoding.UTF8.GetBytes(EncryptionKey);
            aes.Mode = CipherMode.ECB;
            var decryptedBytes = aes.Decrypt(bytes);
            return Encoding.UTF8.GetString(decryptedBytes);
        }
    }
